// BTZ_Search_Fares_AI_SAFE - Reducer final (exploratorio + operativo)
// Inputs desde Set_Input_Fares, data desde $json (HTTP anterior)

const src = $node["Set_Input_Fares"]?.json ?? {};

const search  = ((src.search  ?? "") + "").trim().toLowerCase();
const channel = ((src.channel ?? "") + "").trim();
const enabled = ((src.enabled ?? "true") + "").trim();

// 1) Detectar array de fares (la respuesta actual viene como { fares: [...] })
let faresRaw = [];
if (Array.isArray($json)) faresRaw = $json;
else if ($json && Array.isArray($json.fares)) faresRaw = $json.fares;
else if ($json && Array.isArray($json.data)) faresRaw = $json.data;

// 2) Helper disponibilidad por canal
function isAvailableInChannel(fare, ch) {
  if (!ch) return true; // modo exploración
  const obj = fare?.channels?.[ch];
  if (!obj) return false;
  return obj.available === true;
}

// 3) Filtrado (exploratorio por default)
let filtered = faresRaw.filter(f => {
  if (enabled === "true" && f.disabled === true) return false;

  if (search) {
    const name = ((f.name ?? "") + "").toLowerCase();
    const idx  = ((f.indexableName ?? "") + "").toLowerCase();
    if (!name.includes(search) && !idx.includes(search)) return false;
  }

  // si channel viene, modo operativo: solo disponibles
  if (channel && !isAvailableInChannel(f, channel)) return false;

  return true;
});

// 4) Orden data-driven: ord asc, luego name
filtered = filtered
  .sort((a, b) => {
    const ao = Number(a.ord ?? 999999);
    const bo = Number(b.ord ?? 999999);
    if (ao !== bo) return ao - bo;
    return ((a.name ?? "") + "").localeCompare((b.name ?? "") + "");
  })
  .slice(0, 20); // AI-SAFE

// 5) Compactar fares + extra útil (maxQty por canal si existe)
const fares = filtered.map(f => {
  const chObj = channel ? f?.channels?.[channel] : null;
  return {
    fareId: f._id,
    name: f.name,
    isBaseFare: f.isBaseFare,
    defaultQty: f.defaultQty,
    ord: f.ord,
    disabled: f.disabled,
    availableInChannel: isAvailableInChannel(f, channel),
    maxQtyInChannel: chObj?.maxQty ?? null,
    productIds: f.productIds
  };
});

// 6) fareIds listos para Trips (qty nunca 0)
const allFareIds = fares.map(x => {
  const qty = Number(x.defaultQty);
  const safeQty = Number.isFinite(qty) && qty > 0 ? qty : 1;
  return `${x.fareId}:${safeQty}`;
});

// first: base fare si existe
const base = fares.find(x => x.isBaseFare) || fares[0];
const firstFareIds = base
  ? `${base.fareId}:${(Number(base.defaultQty) > 0 ? Number(base.defaultQty) : 1)}`
  : "";

// recommended (exploratorio): igual a all
const recommendedFareIds = allFareIds;

return [
  {
    json: {
      search,
      channel,
      enabled,
      count: fares.length,
      fares,
      fareIds: {
        all: allFareIds,
        available: allFareIds,
        recommended: recommendedFareIds,
        first: firstFareIds
      }
    }
  }
];

